( find . -type f \( -name "*.c" -o -name "*.h" -o -name "*.cpp" -o -name "*.hpp" \) | grep -vE 'node_modules|venv|__pycache__|.git|.vscode|build|dist' | xargs grep -vE '^[[:space:]]*$|^[[:space:]]*//' 2>/dev/null | wc -l; find . -type f -name "*.py" | grep -vE 'node_modules|venv|__pycache__|.git|.vscode|build|dist' | xargs grep -vE '^[[:space:]]*$|^[[:space:]]*#' 2>/dev/null | wc -l ) | awk 'NR==1{cc=$1} NR==2{py=$1} END{print "C/C++ lines:", cc, "Python lines:", py}'
